    private void jButton1ActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_jButton1ActionPerformed
        // TODO add your handling code here:
        String x = Integer.toString(Mainmenu.ethic);
        String y = Integer.toString(Mainmenu.unethic);
        jLabel3.setText(x);
        jLabel4.setText(y);
        if (Mainmenu.unethic<=2){
            jLabel5.setText("The Tech Optimist");
            jTextArea1.setText("You see technology as largely a force for good. You tend to trust that companies \n and developers have good intentions.");
        }else if (Mainmenu.unethic<=4 && Mainmenu.ethic>=4){
            jLabel5.setText("The Cautious Realist");
            jTextArea1.setText("You see both the benefits and dangers of technology. You believe progress is good, \n but needs rules and accountability.");
        }else if (Mainmenu.unethic<=6 && Mainmenu.ethic>=2){
            jLabel5.setText("The Critical Thinker");
            jTextArea1.setText(" You are skeptical of how technology is being used. You believe the tech industry needs serious \n reform to protect people.");
        }else if (Mainmenu.unethic<=8 && Mainmenu.ethic>=1 ){
            jLabel5.setText("The Ethics Watchdog");
            jTextArea1.setText("You believe technology is causing more harm than good right now. \n You think strong laws and ethical standards are urgently needed.");
        }
    }//GEN-LAST:event_jButton1ActionPerformed

